5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_MULTIPLIER = 1.1;
22	const FIRST_INSURANCE_RATE = 0.1;
23	const CURSE_SURCHARGE_RATE = 0.5;
24	
25	// A main item's premium: its base premium plus item-specific surcharges, each
26	// applied additively to the base (first insurance always; curse if cursed).
27	const mainItemPremium = (item: Item): number => {
28	  const base = BASE_PREMIUMS[item.type];
29	  const curseRate = item.cursed ? CURSE_SURCHARGE_RATE : 0;
30	  return base * (1 + FIRST_INSURANCE_RATE + curseRate);
31	};
32	
33	const COMPONENT_TYPES = ["rune", "moonstone"];
34	const COMPONENT_BASE_PREMIUM = 25;
35	const COMPONENT_BLOCK_SIZE = 3;
36	const COMPONENT_BLOCK_PREMIUM = 60;
37	
38	const isComponent = (item: Item): boolean =>
39	  COMPONENT_TYPES.includes(item.type);
40	
41	// Base premium for `count` alike components: a block premium applies only for
42	// exactly one block's worth (3) of components; otherwise each is priced individually.
43	const componentBasePremium = (count: number): number => {
44	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
45	  return count * COMPONENT_BASE_PREMIUM;
46	};
47	
48	const countByType = (items: Item[]): Map<string, number> => {
49	  const counts = new Map<string, number>();
50	  for (const item of items) {
51	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
52	  }
53	  return counts;
54	};
55	
56	// The block rule is per-type ("alike" = same type), so price each type's count
57	// independently and sum across types.
58	const componentItemsBase = (componentItems: Item[]): number =>
59	  [...countByType(componentItems).values()].reduce(
60	    (base, count) => base + withFirstInsurance(componentBasePremium(count)),
61	    0,
62	  );
63	
64	// Every item is treated as first insurance today, so the 10% surcharge is
65	// applied uniformly to each base premium.
66	const withFirstInsurance = (basePremium: number): number =>
67	  basePremium * FIRST_INSURANCE_MULTIPLIER;
68	
69	// Round up in MHPCO's favour, guarding against floating-point noise
70	// (e.g. 197.50000000001 should still round to 198, not 199).
71	const roundUpInMHPCOFavor = (amount: number): number =>
72	  Math.ceil(Number(amount.toFixed(6)));
73	
74	export const quote = (
75	  items: Item[],
76	  customer: Customer,
77	  contractIndex: number,
78	): number => {
79	  const mainItems = items.filter((item) => !isComponent(item));
80	  const componentItems = items.filter((item) => isComponent(item));
81	
82	  const mainBase = mainItems.reduce(
83	    (sum, item) => sum + mainItemPremium(item),
84	    0,
85	  );
86	  const componentBase = componentItemsBase(componentItems);
87	
88	  return roundUpInMHPCOFavor(mainBase + componentBase + PROCESSING_FEE);
89	};
90	
91	export const claim = (): number => {
92	  return undefined as unknown as number;
93	};
